parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "complianceStatus": {
      "type": "string",
      "enum": ["COMPLIANT", "WARNING", "REVIEW_REQUIRED", "SUSPENSION_RECOMMENDED"],
      "description": "The compliance status of the seller"
    },
    "riskScore": {
      "type": "number",
      "minimum": 0,
      "maximum": 100,
      "description": "Risk score from 0 to 100"
    },
    "reasoning": {
      "type": "string",
      "description": "Explanation for the compliance assessment"
    },
    "recommendedAction": {
      "type": "string",
      "description": "Recommended action to take"
    },
    "biasFlags": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Array of potential bias flags identified"
    },
    "contextualFactors": {
      "type": "object",
      "description": "Additional contextual factors considered in the assessment"
    }
  },
  "required": ["complianceStatus", "riskScore", "reasoning", "recommendedAction", "biasFlags", "contextualFactors"]
}

